import { Platform } from 'react-native';

const BASE_API_URL = 'https://api.example.com';
const LOCAL_IOT_URL = 'http://192.168.x.x';

const API_HEADERS = {
  'Content-Type': 'application/json',
};

async function fetchData(url, options = {}) {
  try {
    const response = await fetch(url, {
      ...options,
      headers: {
        ...API_HEADERS,
        ...(options.headers || {}),
      },
    });

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    return await response.json();
  } catch (error) {
    console.error('Error fetching data:', error);
    throw error;
  }
}

export async function fetchApiData(endpoint, options = {}) {
  const fullUrl = `${BASE_API_URL}/${endpoint}`;
  return fetchData(fullUrl, options);
}

export async function fetchIoTData(path, options = {}) {
  let url = `${LOCAL_IOT_URL}${path}`;

  if (Platform.OS === 'ios') {
    // Assuming iOS can handle HTTPS
    url = url.replace('http://', 'https://');
  }

  return fetchData(url, options);
}